package com.practice.core.service;

import com.fasterxml.jackson.databind.*;import com.practice.core.entity.*;import com.practice.core.dao.*;import jakarta.persistence.criteria.Predicate;import org.springframework.beans.factory.annotation.Value;import org.springframework.data.domain.*;import org.springframework.data.jpa.domain.Specification;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.*;import org.springframework.transaction.support.*;import java.net.URI;import java.net.http.*;import java.nio.charset.StandardCharsets;import java.nio.file.*;import java.time.*;import java.util.*;import java.util.regex.*;import java.util.stream.*;

@Service
public class PlatformCoreService {
    final DeviceDao devices; final ProductDao products; final ProductCategoryDao categories; final DeviceAttributeDao attributes; final DeviceGroupDao groups; final TelemetryDao telemetry; final RuleDao rules; final AlarmDao alarms; final RuleAuditDao audits; final TaskJobDao tasks; final TaskLogDao taskLogs; final OperationLogDao opLogs; final UserDao users; final AiAgentDao aiAgents; final RealtimeEventService realtimeEvents;
    final ObjectMapper mapper = new ObjectMapper();
    @Value("${app.ai.enabled:true}") boolean aiEnabled; @Value("${app.ai.base-url:https://maas.icompify.com:32788/v1}") String aiBaseUrl; @Value("${app.ai.model:deepseek-v4-flash}") String aiModel; @Value("${app.ai.api-key:}") String aiApiKey; @Value("${app.ai.timeout-ms:25000}") long aiTimeoutMs; @Value("${app.ai.allow-local-key-file:false}") boolean aiAllowLocalKeyFile; @Value("${app.device.offline-threshold-seconds:60}") long offlineThresholdSeconds;
    public PlatformCoreService(DeviceDao devices, ProductDao products, ProductCategoryDao categories, DeviceAttributeDao attributes, DeviceGroupDao groups, TelemetryDao telemetry, RuleDao rules, AlarmDao alarms, RuleAuditDao audits, TaskJobDao tasks, TaskLogDao taskLogs, OperationLogDao opLogs, UserDao users, AiAgentDao aiAgents, RealtimeEventService realtimeEvents){this.devices=devices;this.products=products;this.categories=categories;this.attributes=attributes;this.groups=groups;this.telemetry=telemetry;this.rules=rules;this.alarms=alarms;this.audits=audits;this.tasks=tasks;this.taskLogs=taskLogs;this.opLogs=opLogs;this.users=users;this.aiAgents=aiAgents;this.realtimeEvents=realtimeEvents;}
    @Transactional(noRollbackFor=RuntimeException.class) public Map<String,Object> login(String username,String password,String token,String ip){SysUser u=users.findByUsername(username);boolean ok=u!=null&&Objects.equals(u.password,password);op("系统设置","登录",username,ok?"用户登录成功，来源："+ip:"用户登录失败，来源："+ip);if(!ok)throw new RuntimeException("用户名或密码错误");Map<String,Object> user=new LinkedHashMap<>();user.put("id",u.id);user.put("username",u.username);user.put("name",u.name);user.put("realName",u.realName==null?username:u.realName);user.put("role",u.roleName==null||u.roleName.isBlank()?"":u.roleName);user.put("roleName",u.roleName==null||u.roleName.isBlank()?"":u.roleName);user.put("status",u.status);user.put("createdAt",u.createdAt);user.put("updatedAt",u.updatedAt);Map<String,Object> result=new LinkedHashMap<>();result.put("token",token);result.put("tokenType","Bearer");result.put("username",username);result.put("realName",user.get("realName"));result.put("role",user.get("role"));result.put("roleName",user.get("roleName"));result.put("user",user);return result;}
    @Transactional public Map<String,Object> simulate(Map<String,Object> req){return processTelemetry(req,"数据中心","模拟上报","admin");}
    @Transactional public Map<String,Object> report(Map<String,Object> req){String operator=str(req.get("deviceKey"));if(operator.isBlank())operator=str(req.get("deviceCode"));if(operator.isBlank())operator="device";return processTelemetry(req,"设备接入","设备上报",operator);}
    Map<String,Object> processTelemetry(Map<String,Object> req,String module,String action,String operator){Device device=resolveDevice(req);List<String> dataErrors=attributeErrors(device,req);TelemetryData data=new TelemetryData();data.deviceId=device.id;data.deviceName=device.name;data.temperature=safeNum(req.get("temperature"));data.humidity=safeNum(req.get("humidity"));data.pressure=safeNum(req.get("pressure"));data.dataStatus=dataErrors.isEmpty()?"NORMAL":"ABNORMAL";data.dataMessage=String.join("；",dataErrors);data.payload=payload(req);telemetry.save(data);device.status="ONLINE";device.lastOnlineAt=LocalDateTime.now();devices.save(device);List<Alarm> created=new ArrayList<>();if(dataErrors.isEmpty())for(Rule rule:boundRules(device)){boolean hit=ruleHit(rule,req,data);RuleAudit audit=new RuleAudit();audit.name="规则审计-"+rule.name;audit.ruleId=rule.id;audit.deviceId=device.id;audit.status=hit?"HIT":"PASS";audit.result=audit.status;String ruleAction=str(rule.action).isBlank()?"生成告警":str(rule.action);audit.detail=ruleDetail(rule,req,data)+"，动作："+ruleAction;audits.save(audit);if(hit&&!"仅记录规则审计".equals(ruleAction)){Alarm alarm=new Alarm();alarm.name="阈值告警-"+device.name;alarm.code="ALM-"+System.currentTimeMillis();alarm.status="OPEN";alarm.deviceId=device.id;alarm.deviceName=device.name;alarm.ruleId=rule.id;alarm.level=rule.alarmLevel;alarm.type="THRESHOLD";alarm.ruleName=rule.name;alarm.content=audit.detail+"，触发规则："+rule.name;alarms.save(alarm);created.add(alarm);}}op(module,action,operator,"设备"+device.name+"上报遥测数据"+(dataErrors.isEmpty()?"":"，数据异常："+data.dataMessage));broadcastTelemetryEvent(device,data,created);return Map.of("telemetry",data,"alarms",created,"dataErrors",dataErrors);}
    Device resolveDevice(Map<String,Object> req){String deviceKey=str(req.get("deviceKey"));if(!deviceKey.isBlank()){Device device=devices.findByDeviceKey(deviceKey);if(device!=null)return device;}String deviceCode=str(req.get("deviceCode"));if(!deviceCode.isBlank()){Device device=devices.findByCode(deviceCode);if(device!=null)return device;}String deviceId=str(req.get("deviceId"));if(!deviceId.isBlank())return devices.findById(Long.valueOf(deviceId)).orElseThrow(()->new RuntimeException("设备不存在"));throw new RuntimeException("设备不存在，请提供 deviceId、deviceKey 或 deviceCode");}
    String payload(Map<String,Object> req){try{return mapper.writeValueAsString(req);}catch(Exception ignored){return String.valueOf(req);}}
    void broadcastTelemetryEvent(Device device,TelemetryData data,List<Alarm> created){Map<String,Object> telemetryData=new LinkedHashMap<>();telemetryData.put("id",data.id);telemetryData.put("deviceId",data.deviceId);telemetryData.put("deviceName",data.deviceName);telemetryData.put("temperature",data.temperature);telemetryData.put("humidity",data.humidity);telemetryData.put("pressure",data.pressure);telemetryData.put("payload",data.payload);telemetryData.put("reportTime",String.valueOf(data.reportTime));Map<String,Object> event=new LinkedHashMap<>();event.put("deviceId",device.id);event.put("deviceName",device.name);event.put("telemetryId",data.id);event.put("telemetry",telemetryData);event.put("alarmCount",created.size());event.put("hasAlarm",!created.isEmpty());event.put("hasHighAlarm",created.stream().anyMatch(a->"HIGH".equals(a.level)||"高".equals(a.level)));if(TransactionSynchronizationManager.isSynchronizationActive())TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization(){@Override public void afterCommit(){realtimeEvents.broadcast("telemetry",event);}});else realtimeEvents.broadcast("telemetry",event);}
    public Map<String,Object> summary(){refreshDeviceStatuses();return Map.of("products",products.count(),"groups",groups.count(),"devices",devices.count(),"onlineDevices",devices.countByStatus("ONLINE"),"alarms",alarms.count(),"openAlarms",alarms.countByStatus("OPEN"),"telemetryToday",telemetry.countByReportTimeAfter(LocalDate.now().atStartOfDay()),"tasks",tasks.count());}
    public Map<String,Object> charts(){refreshDeviceStatuses();List<Device> ds=devices.findAll();Map<String,Long> byStatus=ds.stream().collect(Collectors.groupingBy(x->Optional.ofNullable(x.status).orElse("UNKNOWN"),Collectors.counting()));List<Alarm> as=alarms.findAll();Map<String,Long> byLevel=as.stream().collect(Collectors.groupingBy(x->Optional.ofNullable(x.level).orElse("INFO"),Collectors.counting()));List<LocalDate> dayDates=IntStream.rangeClosed(0,6).mapToObj(i->LocalDate.now().minusDays(6-i)).toList();List<String> days=dayDates.stream().map(LocalDate::toString).toList();LocalDateTime windowStart=dayDates.get(0).atStartOfDay().minusNanos(1);Map<LocalDate,Long> messageCounts=telemetry.findByReportTimeAfter(windowStart).stream().filter(x->x.reportTime!=null).collect(Collectors.groupingBy(x->x.reportTime.toLocalDate(),Collectors.counting()));Map<LocalDate,Long> deviceCounts=devices.findByCreatedAtAfter(windowStart).stream().filter(x->x.createdAt!=null).collect(Collectors.groupingBy(x->x.createdAt.toLocalDate(),Collectors.counting()));Map<LocalDate,Long> alarmCounts=alarms.findByCreatedAtAfter(windowStart).stream().filter(x->x.createdAt!=null).collect(Collectors.groupingBy(x->x.createdAt.toLocalDate(),Collectors.counting()));return Map.of("deviceStatus",byStatus,"alarmLevel",byLevel,"days",days,"messageTrend",trend(dayDates,messageCounts),"deviceGrowth",trend(dayDates,deviceCounts),"alarmTrend",trend(dayDates,alarmCounts),"recentTelemetry",telemetry.findTop50ByOrderByReportTimeDesc(),"recentAlarms",alarms.findTop20ByOrderByCreatedAtDesc());}
    public List<TelemetryData> recentTelemetry(){return telemetry.findAllByOrderByReportTimeDesc();} public List<TaskLog> taskLogs(){return taskLogs.findTop50ByOrderByExecuteTimeDesc();}
    public Map<String,Object> telemetryPage(Map<String,String> q){Specification<TelemetryData> spec=telemetrySpec(q);Page<TelemetryData> pageData=telemetry.findAll(spec,pageable(q,"reportTime"));return pageResult(pageData);}
    public Map<String,Object> telemetryStats(Map<String,String> q){List<TelemetryData> rows=telemetry.findAll(telemetrySpec(q));Map<String,Long> status=rows.stream().collect(Collectors.groupingBy(this::telemetryAlarmStatus,LinkedHashMap::new,Collectors.counting()));Map<String,Long> deviceTrend=rows.stream().filter(x->x.reportTime!=null).collect(Collectors.groupingBy(x->x.reportTime.toLocalDate().toString(),TreeMap::new,Collectors.counting()));return Map.of("total",rows.size(),"alarmSummary",fillStatus(status,List.of("正常","低","中","高","数据异常")),"deviceTrend",deviceTrend);}
    public Map<String,Object> alarmPage(Map<String,String> q){Specification<Alarm> spec=alarmSpec(q);Page<Alarm> pageData=alarms.findAll(spec,pageable(q,"createdAt"));return pageResult(pageData);}
    public Map<String,Object> alarmStats(Map<String,String> q){List<Alarm> rows=alarms.findAll(alarmSpec(q));Map<String,Long> byStatus=rows.stream().collect(Collectors.groupingBy(x->Optional.ofNullable(x.status).orElse("OPEN"),LinkedHashMap::new,Collectors.counting()));Map<String,Long> byLevel=rows.stream().collect(Collectors.groupingBy(x->Optional.ofNullable(x.level).orElse("INFO"),LinkedHashMap::new,Collectors.counting()));return Map.of("total",rows.size(),"statusSummary",byStatus,"levelSummary",byLevel);}
    public Map<String,Object> operationLogPage(Map<String,String> q){Specification<OperationLog> spec=operationLogSpec(q);Page<OperationLog> pageData=opLogs.findAll(spec,pageable(q,"createdAt"));return pageResult(pageData);}
    public Map<String,Object> operationLogStats(Map<String,String> q){List<OperationLog> rows=opLogs.findAll(operationLogSpec(q));Map<String,Long> byAction=rows.stream().collect(Collectors.groupingBy(x->Optional.ofNullable(x.action).orElse("未知操作"),LinkedHashMap::new,Collectors.counting()));return Map.of("total",rows.size(),"actionSummary",byAction);}
    public Map<String,Object> ruleAuditPage(Map<String,String> q){Specification<RuleAudit> spec=ruleAuditSpec(q);Page<RuleAudit> pageData=audits.findAll(spec,pageable(q,"createdAt"));return pageResult(pageData);}
    @Transactional public Alarm handleAlarm(Long id,Map<String,Object> body){return updateAlarmStatus(id,"CLOSED",body);}
    @Transactional public Alarm updateAlarmStatus(Long id,String status,Map<String,Object> body){Alarm a=alarms.findById(id).orElseThrow();String next=Optional.ofNullable(status).orElse("CLOSED").toUpperCase();LocalDateTime now=LocalDateTime.now();a.status=next;a.handler=String.valueOf(body.getOrDefault("handler","admin"));a.remark=String.valueOf(body.getOrDefault("remark",statusText(next)));if("ACKNOWLEDGED".equals(next))a.acknowledgedAt=now;else if("PROCESSING".equals(next))a.processingAt=now;else if("RECOVERED".equals(next)){a.recoveredAt=now;if(a.createdAt!=null)a.durationSeconds=Duration.between(a.createdAt,now).getSeconds();}else if("CLOSED".equals(next)){a.handledAt=now;if(a.createdAt!=null)a.durationSeconds=Duration.between(a.createdAt,now).getSeconds();}a.handlingRecord=appendHandlingRecord(a.handlingRecord,now,a.handler,statusText(next),a.remark);op("规则引擎","告警状态流转",a.handler,a.name+" -> "+next);return alarms.save(a);}
    @Transactional public List<Device> listDevices(){refreshDeviceStatuses();return devices.findAll();}
    @Scheduled(fixedDelayString="${app.device.status-refresh-ms:30000}") @Transactional public void refreshDeviceStatuses(){LocalDateTime cutoff=LocalDateTime.now().minusSeconds(offlineThresholdSeconds);devices.findAll().stream().filter(d->"ONLINE".equals(d.status)&&(d.lastOnlineAt==null||d.lastOnlineAt.isBefore(cutoff))).forEach(d->{d.status="OFFLINE";devices.save(d);});}
    @Transactional public TaskJob switchTask(Long id,boolean running){return switchTask(id,running,"admin");} @Transactional public TaskJob switchTask(Long id,boolean running,String operator){TaskJob t=tasks.findById(id).orElseThrow();t.running=running;t.status=running?"RUNNING":"STOPPED";t.lastResult=running?"任务已启动，等待调度":"任务已停止";tasks.save(t);TaskLog l=new TaskLog();l.name="任务日志-"+t.name;l.taskId=id;l.status="SUCCESS";l.result=t.lastResult;l.detail="模拟执行策略："+t.cron;taskLogs.save(l);op("任务中心",running?"启动任务":"停止任务",operator,t.name);return t;} @Transactional public void op(String module,String action,String operator,String detail){OperationLog l=new OperationLog();l.name=module+"-"+action;l.moduleName=module;l.action=action;l.operator=str(operator).isBlank()?"admin":operator;l.detail=detail;opLogs.save(l);}
    public Map<String,Object> aiChat(Map<String,Object> req){String operator=str(req.get("operator"));String agentCode=str(req.get("agentCode"));String message=str(req.get("message"));String context=str(req.get("context"));AiAgent agent=agentCode.isBlank()?null:aiAgents.findByCode(agentCode);String requestedModel=str(req.get("model"));String model=!requestedModel.isBlank()?requestedModel:(agent!=null&&agent.modelName!=null&&!agent.modelName.isBlank()?agent.modelName:aiModel);if(model==null||model.isBlank())model="deepseek-v4-flash";op("扩展能力","使用智能体",operator,(agent==null?"默认智能体":agent.name)+"，模型："+model);if(agent!=null&&(Boolean.FALSE.equals(agent.enabled)||"DISABLED".equals(agent.status)))return demoAi(agent,message,model,"该智能体暂未启用，已切换为本地演示建议");if(!aiEnabled)return demoAi(agent,message,model,"智能服务暂未启用，已切换为本地演示建议");String key=resolveAiKey(req);if(key.isBlank())return demoAi(agent,message,model,"智能服务配置待完善，已切换为本地演示建议");try{String base=Optional.ofNullable(str(req.get("baseUrl")).isBlank()?aiBaseUrl:str(req.get("baseUrl"))).orElse("https://maas.icompify.com:32788/v1").replaceAll("/+$","");String system=agent!=null&&agent.systemPrompt!=null&&!agent.systemPrompt.isBlank()?agent.systemPrompt:"你是工业物联网智能平台的智能助手，请用中文给出简洁、可执行的建议。";List<Map<String,String>> messages=new ArrayList<>();messages.add(Map.of("role","system","content",system));if(!context.isBlank())messages.add(Map.of("role","user","content","业务上下文："+context));messages.add(Map.of("role","user","content",message.isBlank()?"请结合工业物联网场景给出建议":message));Map<String,Object> payload=new LinkedHashMap<>();payload.put("model",model);payload.put("messages",messages);payload.put("stream",false);payload.put("max_tokens",500);payload.put("temperature",0.3);HttpClient client=HttpClient.newBuilder().connectTimeout(Duration.ofMillis(aiTimeoutMs)).build();HttpRequest request=HttpRequest.newBuilder(URI.create(base+"/chat/completions")).timeout(Duration.ofMillis(aiTimeoutMs)).header("Authorization","Bearer "+key).header("Content-Type","application/json").POST(HttpRequest.BodyPublishers.ofString(mapper.writeValueAsString(payload),StandardCharsets.UTF_8)).build();HttpResponse<String> response=client.send(request,HttpResponse.BodyHandlers.ofString(StandardCharsets.UTF_8));if(response.statusCode()<200||response.statusCode()>=300)return demoAi(agent,message,model,"智能服务响应较慢，已切换为本地演示建议");JsonNode content=mapper.readTree(response.body()).path("choices").path(0).path("message").path("content");String reply=content.asText("").trim();if(reply.isBlank())return demoAi(agent,message,model,"智能服务响应较慢，已切换为本地演示建议");return Map.of("reply",reply,"source","LIVE","model",model,"notice","智能服务已生成建议");}catch(Exception ignored){return demoAi(agent,message,model,"智能服务响应较慢，已切换为本地演示建议");}}
    public Map<String,Object> aiModels(Map<String,Object> req){String operator=str(req.get("operator"));op("扩展能力","读取智能体模型",operator,"测试模型配置");String key=resolveAiKey(req);String base=Optional.ofNullable(str(req.get("baseUrl")).isBlank()?aiBaseUrl:str(req.get("baseUrl"))).orElse("https://maas.icompify.com:32788/v1").replaceAll("/+$","");if(!aiEnabled)return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","智能服务暂未启用，当前显示默认模型");if(key.isBlank())return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","请填写 API Key，或使用本机示例配置");try{HttpClient client=HttpClient.newBuilder().connectTimeout(Duration.ofMillis(Math.min(aiTimeoutMs,10000))).build();HttpRequest request=HttpRequest.newBuilder(URI.create(base+"/models")).timeout(Duration.ofMillis(Math.min(aiTimeoutMs,15000))).header("Authorization","Bearer "+key).GET().build();HttpResponse<String> response=client.send(request,HttpResponse.BodyHandlers.ofString(StandardCharsets.UTF_8));if(response.statusCode()<200||response.statusCode()>=300)return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","智能服务响应较慢，当前显示默认模型");JsonNode data=mapper.readTree(response.body()).path("data");List<String> models=new ArrayList<>();if(data.isArray())data.forEach(x->{String id=x.path("id").asText("");if(!id.isBlank())models.add(id);});if(models.isEmpty())models.add("deepseek-v4-flash");return Map.of("source","LIVE","models",models,"notice","已读取可用模型");}catch(Exception ignored){return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","智能服务响应较慢，当前显示默认模型");}}
    Map<String,Object> demoAi(AiAgent agent,String message,String model,String notice){String scenario=agent==null||agent.scenario==null?"工业物联网":agent.scenario;String reply="【"+scenario+"】本地演示建议：先确认设备在线状态与最近遥测趋势，再核对告警等级、规则阈值和现场处置记录；如问题持续，建议安排巡检并保留处理结论。";if(message!=null&&message.contains("巡检"))reply="【巡检计划】本地演示建议：按设备重要度分组，优先检查离线设备、高频告警设备和关键网关，记录温度、湿度、压力及现场照片，完成后复核未关闭告警。";else if(message!=null&&message.contains("告警"))reply="【告警解释】本地演示建议：结合触发规则、遥测峰值和设备位置判断影响范围，先降载或停机保护，再通知值班人员确认传感器与工况是否异常。";else if(message!=null&&(message.contains("状态")||message.contains("分析")))reply="【设备状态分析】本地演示建议：关注在线率、最近上报时间、告警数量和任务执行结果；若设备长时间无上报，优先检查供电、网络与边缘网关连接。";return Map.of("reply",reply,"source","DEMO","model",model==null?"deepseek-v4-flash":model,"notice",notice);} String resolveAiKey(Map<String,Object> req){String requestKey=str(req.get("apiKey"));if(!requestKey.isBlank())return requestKey;String key=Optional.ofNullable(aiApiKey).orElse("").trim();if(!key.isBlank()||!aiAllowLocalKeyFile)return key;try{Path cwd=Path.of("").toAbsolutePath();String fileName="接口文档和API-KEY.txt";List<Path> candidates=new ArrayList<>();if(cwd.getParent()!=null)candidates.add(cwd.getParent().resolve(fileName));if(cwd.getParent()!=null&&cwd.getParent().getParent()!=null)candidates.add(cwd.getParent().getParent().resolve(fileName));Pattern p=Pattern.compile("API-KEY\\s*[:：]\\s*([^\\s]+)");for(Path path:candidates)if(Files.isRegularFile(path)){Matcher m=p.matcher(Files.readString(path,StandardCharsets.UTF_8));if(m.find())return m.group(1).trim();}}catch(Exception ignored){}return "";}
    Pageable pageable(Map<String,String> q,String defaultSortField){int page=Math.max(0,parseInt(q.get("page"),1)-1);int size=Math.min(200,Math.max(1,parseInt(q.get("size"),20)));String sortField=sortField(q.get("sortBy"),defaultSortField);String direction=q.getOrDefault("direction",q.getOrDefault("sortOrder","desc"));Sort sort="asc".equalsIgnoreCase(direction)||"ascending".equalsIgnoreCase(direction)?Sort.by(sortField).ascending():Sort.by(sortField).descending();return PageRequest.of(page,size,sort);}
    Map<String,Object> pageResult(Page<?> page){Map<String,Object> result=new LinkedHashMap<>();result.put("content",page.getContent());result.put("total",page.getTotalElements());result.put("page",page.getNumber()+1);result.put("size",page.getSize());result.put("pages",page.getTotalPages());return result;}
    Specification<TelemetryData> telemetrySpec(Map<String,String> q){Set<Long> ids=matchedDeviceIds(q);return (root,query,cb)->{List<Predicate> ps=new ArrayList<>();String deviceName=str(q.get("deviceName"));String keyword=str(q.get("keyword"));String metric=str(q.get("metric"));if(!deviceName.isBlank())ps.add(cb.like(cb.lower(root.get("deviceName").as(String.class)),"%"+deviceName.toLowerCase()+"%"));if(!keyword.isBlank())ps.add(cb.or(cb.like(cb.lower(root.get("deviceName").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("payload").as(String.class)),"%"+keyword.toLowerCase()+"%")));if(ids!=null)ps.add(ids.isEmpty()?cb.disjunction():root.get("deviceId").in(ids));if(!metric.isBlank()){if(List.of("temperature","humidity","pressure").contains(metric))ps.add(cb.isNotNull(root.get(metric)));else ps.add(cb.like(root.get("payload").as(String.class),"%\""+metric+"\"%"));}return cb.and(ps.toArray(Predicate[]::new));};}
    Specification<Alarm> alarmSpec(Map<String,String> q){Set<Long> ids=matchedDeviceIds(q);return (root,query,cb)->{List<Predicate> ps=new ArrayList<>();String keyword=str(q.get("keyword"));String status=str(q.get("status"));String level=str(q.get("level"));String deviceName=str(q.get("deviceName"));if(!keyword.isBlank())ps.add(cb.or(cb.like(cb.lower(root.get("name").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("deviceName").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("content").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("ruleName").as(String.class)),"%"+keyword.toLowerCase()+"%")));if(!deviceName.isBlank())ps.add(cb.like(cb.lower(root.get("deviceName").as(String.class)),"%"+deviceName.toLowerCase()+"%"));if(ids!=null)ps.add(ids.isEmpty()?cb.disjunction():root.get("deviceId").in(ids));if(!status.isBlank())ps.add(cb.equal(root.get("status"),status));if(!level.isBlank())ps.add(cb.equal(root.get("level"),level));return cb.and(ps.toArray(Predicate[]::new));};}
    Specification<OperationLog> operationLogSpec(Map<String,String> q){return (root,query,cb)->{List<Predicate> ps=new ArrayList<>();String keyword=str(q.get("keyword"));if(!keyword.isBlank())ps.add(cb.or(cb.like(cb.lower(root.get("name").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("moduleName").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("action").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("operator").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("detail").as(String.class)),"%"+keyword.toLowerCase()+"%")));return cb.and(ps.toArray(Predicate[]::new));};}
    Specification<RuleAudit> ruleAuditSpec(Map<String,String> q){return (root,query,cb)->{List<Predicate> ps=new ArrayList<>();String keyword=str(q.get("keyword"));String status=str(q.get("status"));if(!keyword.isBlank())ps.add(cb.or(cb.like(cb.lower(root.get("name").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("status").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("result").as(String.class)),"%"+keyword.toLowerCase()+"%"),cb.like(cb.lower(root.get("detail").as(String.class)),"%"+keyword.toLowerCase()+"%")));if(!status.isBlank())ps.add(cb.equal(root.get("status"),status));return cb.and(ps.toArray(Predicate[]::new));};}
    Set<Long> matchedDeviceIds(Map<String,String> q){String productGroup=str(q.get("productGroup"));String deviceGroup=str(q.get("deviceGroup"));if(productGroup.isBlank()&&deviceGroup.isBlank())return null;Map<Long,Product> productMap=products.findAll().stream().collect(Collectors.toMap(p->p.id,p->p));Map<Long,String> categoryNames=categories.findAll().stream().collect(Collectors.toMap(c->c.id,c->c.name));Map<Long,String> groupNames=groups.findAll().stream().collect(Collectors.toMap(g->g.id,g->g.name));return devices.findAll().stream().filter(d->{Product p=productMap.get(d.productId);String category=p==null?null:categoryNames.get(p.categoryId);String group=groupNames.get(d.groupId);return (productGroup.isBlank()||productGroup.equals(category))&&(deviceGroup.isBlank()||deviceGroup.equals(group));}).map(d->d.id).collect(Collectors.toSet());}
    String telemetryAlarmStatus(TelemetryData row){if("ABNORMAL".equals(row.dataStatus))return"数据异常";Map<String,Object> values=telemetryValues(row);List<Rule> scopedRules=devices.findById(row.deviceId==null?-1L:row.deviceId).map(this::boundRules).orElse(List.of());List<String> hits=scopedRules.stream().filter(r->ruleHit(r,values)).map(r->levelText(r.alarmLevel)).sorted((a,b)->levelRank(b)-levelRank(a)).toList();return hits.isEmpty()?"正常":hits.get(0);}
    Map<String,Long> fillStatus(Map<String,Long> raw,List<String> keys){Map<String,Long> result=new LinkedHashMap<>();keys.forEach(k->result.put(k,raw.getOrDefault(k,0L)));return result;}
    String levelText(String level){return Map.of("HIGH","高","MEDIUM","中","LOW","低","INFO","低").getOrDefault(Optional.ofNullable(level).orElse(""),Optional.ofNullable(level).orElse("低"));}
    int levelRank(String level){return Map.of("高",3,"中",2,"低",1,"正常",0).getOrDefault(level,0);}
    String statusText(String status){return Map.of("ACKNOWLEDGED","已确认","PROCESSING","处理中","RECOVERED","已恢复","CLOSED","已关闭").getOrDefault(status,"已处置");}
    String appendHandlingRecord(String old,LocalDateTime time,String handler,String action,String remark){String line=time.toString().replace('T',' ').substring(0,19)+" "+handler+" "+action+"："+remark;return str(old).isBlank()?line:old+"\n"+line;}
    List<Rule> boundRules(Device device){Set<Long> ids=boundRuleIds(device);if(ids.isEmpty())return List.of();return rules.findAllById(ids).stream().filter(r->Boolean.TRUE.equals(r.enabled)).toList();}
    Set<Long> boundRuleIds(Device device){Set<Long> ids=parseIds(device.ruleIds);if(device.ruleId!=null)ids.add(device.ruleId);if(!ids.isEmpty())return ids;if(device.productId==null)return ids;products.findById(device.productId).ifPresent(product->{ids.addAll(parseIds(product.ruleIds));if(product.ruleId!=null)ids.add(product.ruleId);});return ids;}
    List<String> attributeErrors(Device device,Map<String,Object> req){if(device.groupId==null)return List.of("设备未绑定属性分组");DeviceGroup group=groups.findById(device.groupId).orElse(null);if(group==null)return List.of("设备分组不存在");Set<Long> ids=parseIds(group.attributeIds);if(ids.isEmpty())return List.of("设备分组未配置属性");List<DeviceAttribute> attrs=attributes.findAllById(ids);Set<String> names=attrs.stream().map(a->a.name).collect(Collectors.toSet());Set<String> telemetryKeys=req.keySet().stream().map(String::valueOf).filter(k->!List.of("deviceId","deviceKey","deviceCode","timestamp","time","source","mqttTopic").contains(k)).collect(Collectors.toCollection(LinkedHashSet::new));List<String> errors=new ArrayList<>();for(String key:telemetryKeys)if(!names.contains(key))errors.add("属性["+key+"]不属于设备分组");for(DeviceAttribute attr:attrs){if(!req.containsKey(attr.name))continue;Object raw=req.get(attr.name);if("BOOL".equals(attr.valueType)&&!(raw instanceof Boolean||List.of("true","false","True","False","0","1").contains(String.valueOf(raw))))errors.add("属性["+attr.name+"]必须是布尔值");if("INT".equals(attr.valueType)||"FLOAT".equals(attr.valueType)){Double value=null;try{value=num(raw);}catch(Exception e){errors.add("属性["+attr.name+"]必须是数字");}if(value!=null){if("INT".equals(attr.valueType)&&value.doubleValue()!=Math.rint(value))errors.add("属性["+attr.name+"]必须是整数");boolean minActive=Boolean.TRUE.equals(attr.minEnabled)||(attr.minEnabled==null&&Boolean.TRUE.equals(attr.rangeEnabled));boolean maxActive=Boolean.TRUE.equals(attr.maxEnabled)||(attr.maxEnabled==null&&Boolean.TRUE.equals(attr.rangeEnabled));if(minActive&&attr.minValue!=null&&value<attr.minValue)errors.add("属性["+attr.name+"]不能小于最小值 "+attr.minValue);if(maxActive&&attr.maxValue!=null&&value>attr.maxValue)errors.add("属性["+attr.name+"]不能大于最大值 "+attr.maxValue);}}}return errors;}
    Set<Long> parseIds(String value){Set<Long> ids=new LinkedHashSet<>();if(value==null||value.isBlank())return ids;for(String part:value.split(",")){try{String id=part.trim();if(!id.isBlank())ids.add(Long.valueOf(id));}catch(Exception ignored){}}return ids;}
    int parseInt(String value,int fallback){try{return value==null||value.isBlank()?fallback:Integer.parseInt(value);}catch(Exception ignored){return fallback;}}
    String sortField(String requested,String fallback){String value=str(requested);return List.of("id","createdAt","updatedAt","reportTime","deviceName","level","status","name").contains(value)?value:fallback;}
    boolean ruleHit(Rule rule,Map<String,Object> req,TelemetryData data){return ruleHit(rule,telemetryValues(req,data));}
    boolean ruleHit(Rule rule,Map<String,Object> values){boolean first=conditionHit(values,rule.metric,rule.operator,rule.threshold);if(str(rule.logicOperator).isBlank())return first;boolean second=conditionHit(values,rule.secondMetric,rule.secondOperator,rule.secondThreshold);return "OR".equalsIgnoreCase(rule.logicOperator)?first||second:first&&second;}
    boolean conditionHit(Map<String,Object> values,String metric,String operator,String threshold){Object raw=values.get(metric);if(raw==null||threshold==null)return false;return compareValue(raw,operator,threshold);}
    String ruleDetail(Rule rule,Map<String,Object> req,TelemetryData data){Map<String,Object> values=telemetryValues(req,data);String first=rule.metric+"="+values.get(rule.metric)+" "+rule.operator+" "+rule.threshold;if(str(rule.logicOperator).isBlank())return first;return first+" "+rule.logicOperator+" "+rule.secondMetric+"="+values.get(rule.secondMetric)+" "+rule.secondOperator+" "+rule.secondThreshold;}
    Map<String,Object> telemetryValues(Map<String,Object> req,TelemetryData data){Map<String,Object> values=new LinkedHashMap<>(req);values.put("temperature",data.temperature);values.put("humidity",data.humidity);values.put("pressure",data.pressure);return values;}
    Map<String,Object> telemetryValues(TelemetryData row){Map<String,Object> values=new LinkedHashMap<>();values.put("temperature",row.temperature);values.put("humidity",row.humidity);values.put("pressure",row.pressure);try{if(row.payload!=null)mapper.readValue(row.payload,Map.class).forEach((k,v)->values.put(String.valueOf(k),v));}catch(Exception ignored){}return values;}
    Double metricValue(String metric,Map<String,Object> req,TelemetryData data){return switch(Optional.ofNullable(metric).orElse("")){case "humidity"->data.humidity;case "pressure"->data.pressure;case "temperature"->data.temperature;default->num(req.get(metric));};}
    static String str(Object o){return o==null?"":String.valueOf(o).trim();} static Double num(Object o){return o==null?null:Double.valueOf(String.valueOf(o));} static Double safeNum(Object o){try{return num(o);}catch(Exception ignored){return null;}} static boolean compareValue(Object raw,String op,String threshold){String left=str(raw);String right=str(threshold);try{double v=Double.parseDouble(left);double th=Double.parseDouble(right);return switch(op){case ">="->v>=th;case "<"->v<th;case "<="->v<=th;case "=="->v==th;case "!="->v!=th;default->v>th;};}catch(Exception ignored){boolean equals=left.equalsIgnoreCase(right);return "!=".equals(op)?!equals:equals;}} static List<Map<String,Object>> trend(List<LocalDate> days,Map<LocalDate,Long> counts){return days.stream().map(d->Map.<String,Object>of("name",String.format("%02d-%02d",d.getMonthValue(),d.getDayOfMonth()),"value",counts.getOrDefault(d,0L))).toList();}
}
